sql:
SELECT unit_title
FROM units
WHERE points = (SELECT MAX(points) FROM units);

SELECT AVG(enrollment_count) AS average_enrollment
FROM (
  SELECT unit_id, COUNT(student_id) AS enrollment_count
  FROM enrollments
  GROUP BY unit_id
);

